parameters.functionCode:
const inventory = $input.all()[0].json;
const forecast = $input.all()[1].json;

const shortages = inventory.filter(item => {
  const daysUntilShort = item.currentStock / (forecast.dailyUsage || 1);
  return daysUntilShort < item.leadTimeDays + item.safetyStockDays;
}).map(item => ({
  ...item,
  daysRemaining: Math.floor(item.currentStock / (forecast.dailyUsage || 1)),
  suggestedOrderQty: (forecast.weeklyDemand * 4) - item.currentStock + item.safetyStock
}));

return { shortages, count: shortages.length };

const shortages = $input.first().json.shortages;

const pos = shortages.map(item => ({
  poNumber: 'PO-' + Date.now() + '-' + item.sku.slice(-4),
  supplier: item.preferredSupplier,
  sku: item.sku,
  description: item.description,
  quantity: Math.ceil(item.suggestedOrderQty),
  unitCost: item.lastUnitCost,
  totalCost: Math.ceil(item.suggestedOrderQty) * item.lastUnitCost,
  requiredDate: new Date(Date.now() + (item.leadTimeDays * 24 * 60 * 60 * 1000)).toISOString(),
  notes: 'Auto-generated due to predicted shortage in ' + item.daysRemaining + ' days'
}));

return { pos, totalValue: pos.reduce((a, p) => a + p.totalCost, 0) };

